    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: discriminator property renamed from "Discriminator" to "$type".
        // Keep old name for compatibility with existing documents.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change: id no longer includes discriminator prefix (was "Blog|1", now "1").
        // Preserve old format for existing documents.
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // Breaking change: key property now maps directly to JSON "id",
        // removing the shadow __id property that previously stored it separately.
        // Preserve old shadow property so the key value isn't duplicated/lost.
        modelBuilder.Entity<Blog>().HasShadowId();

        // Breaking change: HasIndex now throws on Cosmos (was silently ignored).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change: sync I/O now throws by default.
        // Suppress until callers are migrated to async.
        optionsBuilder.ConfigureWarnings(w =>
            w.Ignore(Microsoft.EntityFrameworkCore.Diagnostics.CosmosEventId.SyncNotSupported));

        base.OnConfiguring(optionsBuilder);
    }
}
